// Extract phone + message from Meta Cloud API payload (one IIFE — Set-node fields can't reference earlier fields in the same Set)
return items.map((item) => {
  const entry = item.json.body?.entry?.[0] ?? item.json.entry?.[0];
  const change = entry?.changes?.[0]?.value;
  const msg = change?.messages?.[0];
  const phone = msg?.from ?? null;
  let text = null;
  let replyId = null;
  if (msg?.type === 'text') text = msg.text?.body ?? null;
  if (msg?.type === 'interactive') {
    const i = msg.interactive;
    replyId = i?.list_reply?.id ?? i?.button_reply?.id ?? null;
    text = i?.list_reply?.title ?? i?.button_reply?.title ?? null;
  }
  return { json: { phone, text, replyId, messageType: msg?.type ?? 'unknown', raw: msg ?? {} } };
});

// CUSTOMISING: append selection, advance step, prepare next list
const STEPS = ['base','protein','dressing','topping','addon','portion'];
const s = $input.first().json;
const ctx = s.context ?? { step: 'base', selections: {} };
const replyId = $('Extract Message').first().json.replyId;
if (replyId) {
  const step = ctx.step;
  if (!ctx.selections[step]) ctx.selections[step] = [];
  ctx.selections[step].push(replyId);
}
const idx = STEPS.indexOf(ctx.step);
const nextStep = idx < STEPS.length - 1 ? STEPS[idx + 1] : 'summary';
ctx.step = nextStep;
return [{ json: { context: ctx, nextStep, phone: s.phone } }];
